args.sparql:
SELECT ?rating WHERE {
  ?album wdt:P31 wd:Q35120;
         rdfs:label 'Here We Go Again'@en;
         wdt:P10198 ?rating.
}

SELECT ?rating WHERE {
  ?album wdt:P31 wd:Q386724;
         rdfs:label ?title;
         wdt:P10198 ?rating.
  FILTER (LCASE(?title) = "here we go again" && LANG(?title) = "en").
}

SELECT ?rating WHERE {
  ?album wdt:P31 wd:Q386724;
         rdfs:label ?title;
         wdt:P1348 ?rating.
  FILTER (LCASE(?title) = "here we go again" && LANG(?title) = "en").
}

SELECT ?album ?title WHERE {
  ?album wdt:P31 wd:Q386724;
         rdfs:label ?title.
  FILTER (LANG(?title) = 'en' && LCASE(?title) = 'here we go again').
}
